import bcrypt
import json

# Simulated user database
users_db = {}

def register_user(username, password):
    """Register a new user with hashed password"""
    if username in users_db:
        return {"success": False, "message": "User already exists"}

    # Generate salt and hash password
    salt = bcrypt.gensalt()
    hashed_password = bcrypt.hashpw(password.encode('utf-8'), salt)

    users_db[username] = {
        "username": username,
        "password_hash": hashed_password.decode('utf-8'),
        "salt": salt.decode('utf-8')
    }
    return {"success": True, "message": "User registered successfully"}

def authenticate_user(username, password):
    """Authenticate user by verifying password hash"""
    if username not in users_db:
        return {"success": False, "message": "User not found"}

    stored_hash = users_db[username]["password_hash"].encode('utf-8')
    input_password = password.encode('utf-8')

    if bcrypt.checkpw(input_password, stored_hash):
        return {"success": True, "message": "Authentication successful"}
    else:
        return {"success": False, "message": "Invalid password"}

# Demo usage
print("=== Remote User Authentication - Basic ===")
print("\n1. Registering users:")
print(register_user("alice", "securePass123"))
print(register_user("bob", "myPassword456"))

print("\n2. Authentication attempts:")
print(authenticate_user("alice", "securePass123"))
print(authenticate_user("alice", "wrongPassword"))
print(authenticate_user("charlie", "somePass"))
